contracts/AgentNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";

contract AgentNFT is ERC721, ERC721Enumerable, ERC721URIStorage, AccessControl {
    bytes32 public constant UPDATER_ROLE = keccak256("UPDATER_ROLE");
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    uint8 public constant CONTENT_AGENT = 0;
    uint8 public constant TRADING_AGENT = 1;

    uint256 private _nextTokenId;

    struct AgentDNA {
        uint8 agentType;
        string specialization;
        uint256[5] skillScores;
        uint256 level;
        uint256 totalEarnings;
        uint256 jobsCompleted;
        uint256 reputationScore;
        string[] traits;
        uint256 mintedAt;
        address tbaWallet;
    }

    mapping(uint256 => AgentDNA) public agentDNA;

    address public erc6551Registry;
    address public erc6551Implementation;

    uint256 public mintFee = 0.01 ether;

    event AgentMinted(uint256 indexed tokenId, address indexed owner, uint8 agentType, string specialization);
    event AgentEvolved(uint256 indexed tokenId, uint256 newLevel, string newTrait);
    event DNAUpdated(uint256 indexed tokenId, string field);
    event TBACreated(uint256 indexed tokenId, address tbaAddress);

    constructor() ERC721("AgentForge Agent", "AGENT") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(UPDATER_ROLE, msg.sender);
    }

    function mintAgent(
        address to,
        uint8 _agentType,
        string memory _specialization,
        uint256[5] memory _initialSkills,
        string memory _metadataURI
    ) external onlyRole(MINTER_ROLE) returns (uint256) {
        require(to != address(0), "Invalid owner");
        require(_agentType <= 1, "Invalid agent type");

        _nextTokenId += 1;
        uint256 tokenId = _nextTokenId;

        _safeMint(to, tokenId);
        _setTokenURI(tokenId, _metadataURI);

        string[] memory emptyTraits = new string[](0);
        agentDNA[tokenId] = AgentDNA({
            agentType: _agentType,
            specialization: _specialization,
            skillScores: _initialSkills,
            level: 1,
            totalEarnings: 0,
            jobsCompleted: 0,
            reputationScore: 50,
            traits: emptyTraits,
            mintedAt: block.timestamp,
            tbaWallet: address(0)
        });

        emit AgentMinted(tokenId, to, _agentType, _specialization);
        return tokenId;
    }

    function setERC6551Config(address _registry, address _implementation) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_registry != address(0), "Invalid registry");
        require(_implementation != address(0), "Invalid implementation");

        erc6551Registry = _registry;
        erc6551Implementation = _implementation;
    }

    function setTBAWallet(uint256 tokenId, address _tbaWallet) external onlyRole(UPDATER_ROLE) {
        require(_exists(tokenId), "Agent does not exist");
        require(_tbaWallet != address(0), "Invalid TBA wallet");

        agentDNA[tokenId].tbaWallet = _tbaWallet;
        emit TBACreated(tokenId, _tbaWallet);
    }

    function updateSkillScores(uint256 tokenId, uint256[5] memory newScores) external onlyRole(UPDATER_ROLE) {
        require(_exists(tokenId), "Agent does not exist");

        agentDNA[tokenId].skillScores = newScores;
        emit DNAUpdated(tokenId, "skillScores");
    }

    function recordJobCompleted(uint256 tokenId, uint256 earningsWei) external onlyRole(UPDATER_ROLE) {
        require(_exists(tokenId), "Agent does not exist");

        agentDNA[tokenId].jobsCompleted += 1;
        agentDNA[tokenId].totalEarnings += earningsWei;
        emit DNAUpdated(tokenId, "jobCompleted");
    }

    function updateReputationScore(uint256 tokenId, uint256 newScore) external onlyRole(UPDATER_ROLE) {
        require(_exists(tokenId), "Agent does not exist");
        require(newScore <= 100, "Score must be 0-100");

        agentDNA[tokenId].reputationScore = newScore;
        emit DNAUpdated(tokenId, "reputationScore");
    }

    function evolveAgent(uint256 tokenId, uint256 newLevel, string memory newTrait, string memory newMetadataURI)
        external
        onlyRole(UPDATER_ROLE)
    {
        require(_exists(tokenId), "Agent does not exist");
        require(bytes(newTrait).length > 0, "Invalid trait");

        agentDNA[tokenId].level = newLevel;
        agentDNA[tokenId].traits.push(newTrait);
        _setTokenURI(tokenId, newMetadataURI);

        emit AgentEvolved(tokenId, newLevel, newTrait);
    }

    function getAgentDNA(uint256 tokenId) external view returns (AgentDNA memory) {
        require(_exists(tokenId), "Agent does not exist");
        return agentDNA[tokenId];
    }

    function getAgentsByOwner(address owner) external view returns (uint256[] memory) {
        uint256 count = balanceOf(owner);
        uint256[] memory tokenIds = new uint256[](count);

        for (uint256 i = 0; i < count; i++) {
            tokenIds[i] = tokenOfOwnerByIndex(owner, i);
        }

        return tokenIds;
    }

    function totalAgents() external view returns (uint256) {
        return _nextTokenId;
    }

    function _beforeTokenTransfer(address from, address to, uint256 tokenId, uint256 batchSize)
        internal
        override(ERC721, ERC721Enumerable)
    {
        super._beforeTokenTransfer(from, to, tokenId, batchSize);
    }

    function _burn(uint256 tokenId) internal override(ERC721, ERC721URIStorage) {
        super._burn(tokenId);
    }

    function tokenURI(uint256 tokenId) public view override(ERC721, ERC721URIStorage) returns (string memory) {
        return super.tokenURI(tokenId);
    }

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721Enumerable, ERC721URIStorage, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

contracts/ERC6551Account.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "@openzeppelin/contracts/interfaces/IERC1271.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/utils/cryptography/SignatureChecker.sol";
import "@openzeppelin/contracts/utils/introspection/IERC165.sol";
import "./interfaces/IERC6551Account.sol";

contract ERC6551Account is IERC165, IERC1271, IERC6551Account {
    uint256 public state;

    receive() external payable override {}

    function executeCall(address to, uint256 value, bytes calldata data) external payable returns (bytes memory result) {
        require(_isValidSigner(msg.sender), "Not token owner");
        state += 1;

        bool success;
        (success, result) = to.call{value: value}(data);
        require(success, "Call failed");
    }

    function transferERC20(address tokenAddress, address to, uint256 amount) external {
        require(_isValidSigner(msg.sender), "Not token owner");
        state += 1;
        IERC20(tokenAddress).transfer(to, amount);
    }

    function token() public view override returns (uint256 chainId, address tokenContract, uint256 tokenId) {
        bytes memory footer = new bytes(96);
        assembly {
            extcodecopy(address(), add(footer, 0x20), 0x4d, 96)
        }
        return abi.decode(footer, (uint256, address, uint256));
    }

    function owner() public view returns (address) {
        (uint256 chainId, address tokenContract, uint256 tokenId) = token();
        if (chainId != block.chainid) {
            return address(0);
        }
        return IERC721(tokenContract).ownerOf(tokenId);
    }

    function _isValidSigner(address signer) internal view returns (bool) {
        return signer == owner();
    }

    function isValidSigner(address signer, bytes calldata) external view override returns (bytes4) {
        if (_isValidSigner(signer)) {
            return IERC6551Account.isValidSigner.selector;
        }
        return bytes4(0);
    }

    function isValidSignature(bytes32 hash, bytes memory signature) external view override returns (bytes4 magicValue) {
        bool isValid = SignatureChecker.isValidSignatureNow(owner(), hash, signature);
        if (isValid) {
            return IERC1271.isValidSignature.selector;
        }
        return bytes4(0);
    }

    function supportsInterface(bytes4 interfaceId) external pure override returns (bool) {
        return interfaceId == type(IERC165).interfaceId || interfaceId == type(IERC6551Account).interfaceId;
    }
}

contracts/ERC6551Registry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "./interfaces/IERC6551Registry.sol";

contract ERC6551Registry is IERC6551Registry {
    function createAccount(
        address implementation,
        bytes32 salt,
        uint256 chainId,
        address tokenContract,
        uint256 tokenId
    ) external returns (address) {
        bytes memory code = _creationCode(implementation, salt, chainId, tokenContract, tokenId);
        address predicted = _computeAddress(code, salt);

        if (predicted.code.length == 0) {
            address deployed;
            assembly {
                deployed := create2(0, add(code, 0x20), mload(code), salt)
            }
            require(deployed != address(0), "ERC6551: deployment failed");
            predicted = deployed;
        }

        emit ERC6551AccountCreated(predicted, implementation, salt, chainId, tokenContract, tokenId);
        return predicted;
    }

    function account(
        address implementation,
        bytes32 salt,
        uint256 chainId,
        address tokenContract,
        uint256 tokenId
    ) external view returns (address) {
        bytes memory code = _creationCode(implementation, salt, chainId, tokenContract, tokenId);
        return _computeAddress(code, salt);
    }

    function _creationCode(
        address implementation,
        bytes32 salt,
        uint256 chainId,
        address tokenContract,
        uint256 tokenId
    ) internal pure returns (bytes memory) {
        return
            abi.encodePacked(
                hex"3d60ad80600a3d3981f3363d3d373d3d3d363d73",
                implementation,
                hex"5af43d82803e903d91602b57fd5bf3",
                abi.encode(salt, chainId, tokenContract, tokenId)
            );
    }

    function _computeAddress(bytes memory code, bytes32 salt) internal view returns (address) {
        bytes32 hash = keccak256(abi.encodePacked(bytes1(0xff), address(this), salt, keccak256(code)));
        return address(uint160(uint256(hash)));
    }
}

contracts/ForgeToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
        
contract ForgeToken is ERC20, ERC20Burnable, AccessControl {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PLATFORM_ROLE = keccak256("PLATFORM_ROLE");

    uint256 public constant MAX_SUPPLY = 1_000_000_000 * 10 ** 18;
    uint256 public constant INITIAL_SUPPLY = 100_000_000 * 10 ** 18;

    address public treasury;

    mapping(address => uint256) public faucetClaimed;
    uint256 public constant FAUCET_AMOUNT = 10_000 * 10 ** 18;
    uint256 public constant MAX_FAUCET_CLAIMS = 5;

    event TreasuryUpdated(address indexed oldTreasury, address indexed newTreasury);
    event FaucetClaimed(address indexed user, uint256 amount);

    constructor(address _treasury) ERC20("AgentForge Token", "FORGE") {
        require(_treasury != address(0), "Invalid treasury");

        treasury = _treasury;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(PLATFORM_ROLE, msg.sender);

        _mint(_treasury, INITIAL_SUPPLY);
    }

    function claimFaucet() external {
        require(faucetClaimed[msg.sender] < MAX_FAUCET_CLAIMS, "Max faucet claims reached");
        require(totalSupply() + FAUCET_AMOUNT <= MAX_SUPPLY, "Exceeds max supply");

        faucetClaimed[msg.sender] += 1;
        _mint(msg.sender, FAUCET_AMOUNT);

        emit FaucetClaimed(msg.sender, FAUCET_AMOUNT);
    }

    function platformMint(address to, uint256 amount) external onlyRole(PLATFORM_ROLE) {
        require(to != address(0), "Invalid recipient");
        require(totalSupply() + amount <= MAX_SUPPLY, "Exceeds max supply");

        _mint(to, amount);
    }

    function setTreasury(address _treasury) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_treasury != address(0), "Invalid treasury");

        address old = treasury;
        treasury = _treasury;

        emit TreasuryUpdated(old, _treasury);
    }
}

